import sys

def shortest_palindrome(s):
    n = len(s)
    lps = [0] * n
    length = 0  # length of the previous longest prefix suffix

    for i in range(1, n):
        while length > 0 and s[i] != s[length]:
            length = lps[length - 1]
        if s[i] == s[length]:
            length += 1
            lps[i] = length
        else:
            lps[i] = 0

    max_len = lps[-1]
    return s + s[:max_len][::-1]

def main():
    s = sys.stdin.read().strip()
    print(shortest_palindrome(s))

if __name__ == "__main__":
    main()
